// Parallel HTTP Requests using http.batch
// Generated by: /k6.plan scenario=load target=https://httpbin.org sla=p99<600ms
// Updated: Uses environment variables for base URL
// Usage: k6 run --env BASE_URL=https://httpbin.org batch-requests.js

import http from 'k6/http';
import { check, sleep } from 'k6';

const baseUrl = __ENV.BASE_URL || 'https://httpbin.org';

export const options = {
  stages: [
    { duration: '2m', target: 25 },
    { duration: '5m', target: 25 },
    { duration: '2m', target: 0 },
  ],
  thresholds: {
    'http_req_duration': ['p(99)<600'],
    'http_req_failed': ['rate<0.01'],
    'http_reqs': ['rate>20'],
  },
};

export default function batchRequestsScenario() {
  // Execute multiple requests in parallel for better performance
  const responses = http.batch([
    ['GET', `${baseUrl}/get`, null, { tags: { name: 'get-request' } }],
    ['GET', `${baseUrl}/headers`, null, { tags: { name: 'headers-request' } }],
    ['GET', `${baseUrl}/user-agent`, null, { tags: { name: 'user-agent-request' } }],
    ['GET', `${baseUrl}/uuid`, null, { tags: { name: 'uuid-request' } }],
  ]);

  // Check response from GET request
  check(responses[0], {
    'get status is 200': (r) => r.status === 200,
  });

  // Check response from headers request
  check(responses[1], {
    'headers status is 200': (r) => r.status === 200,
  });

  // Check response from user-agent request
  check(responses[2], {
    'user-agent status is 200': (r) => r.status === 200,
  });

  // Check response from uuid request
  check(responses[3], {
    'uuid status is 200': (r) => r.status === 200,
    'uuid format is valid': (r) => r.json('uuid').length === 36,
  });

  sleep(1);
}
